    sendMessage(from, to, text);
    messageInput.value = '';
    messageInput.focus();
  });

  // Enter key on message input
  messageInput?.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') sendBtn?.click();
  });

  // Quick send buttons
